SELECT COUNT(1) AS QUANTIDADE FROM LATTES_ORIENTACAO LO JOIN SERVIDOR S ON S.PK_SIAPE = LO.FK_SIAPE WHERE (LOWER(LO.TIPO) LIKE LOWER('%supervis%') AND (LOWER(LO.TIPO) LIKE LOWER('%estagio%') OR LOWER(LO.TIPO) LIKE LOWER('%estagio%'))) AND LOWER(LO.TIPO) LIKE LOWER('%aproveitamento de horas%') AND S.SIGLA_CAMPUS = 'ANA' AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educacao fisica%' OR LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educacao fisica%') AND LO.ANO >= CAST(CAST(strftime('%Y', DATE('now')) AS INTEGER) AS INT) - 4